class scoped_restore_current_thread
{
public:
  scoped_restore_current_thread ();
  ~scoped_restore_current_thread ();

  /* Disable copy.  */
  scoped_restore_current_thread
    (const scoped_restore_current_thread &) = delete;
  void operator=
    (const scoped_restore_current_thread &) = delete;

private:
  thread_info *m_thread;
  inferior *m_inf;
  frame_id m_selected_frame_id;
  int m_selected_frame_level;
  bool m_was_stopped;
}

